import { forwardRef, useId } from "react";
import { Label as AriaLabel, Text } from "react-aria-components";
import { RadioGroup, type RadioGroupProps } from "../RadioGroup";
import { Legend } from "../Legend";
import type { LegendCustomProps } from "../Legend";
import { Hint } from "../Hint";
import type { HintCustomProps } from "../Hint";
import { ValidationMessage } from "../ValidationMessage";
import type {
  ValidationMessageValidProps,
  ValidationMessageInvalidProps,
} from "../ValidationMessage";
import { RadioButtonTile } from "../RadioButtonTile";
import { RadioButton } from "../RadioButton";
import { _RadioButtonCompact } from "./components/_RadioButtonCompact";
import * as styles from "./RadioButtonFieldset.css";
import { clsx } from "clsx";
import type {
  TileItem,
  TextItem,
  CompactItem,
} from "./RadioButtonFieldset.config";

export type RadioButtonFieldsetLegend = Omit<LegendCustomProps, "asChild">;

export type RadioButtonFieldsetHint = HintCustomProps;

export type RadioButtonFieldsetValidationMessage =
  | ValidationMessageValidProps
  | ValidationMessageInvalidProps;

/**
 * Props specific to the tile variant
 */
interface TileVariantProps {
  /**
   * The visual variant of the radio button group.
   * `tile`: Radio buttons inside tiles with individual borders (RadioButtonTile)
   */
  variant: "tile";

  /**
   * The items for the tile variant
   */
  items: TileItem[];
}

/**
 * Props specific to the text variant
 */
interface TextVariantProps {
  /**
   * The visual variant of the radio button group.
   * `text`: Simple radio buttons with text labels (RadioButton)
   */
  variant: "text";

  /**
   * The items for the text variant
   */
  items: TextItem[];
}

/**
 * Props specific to the compact variant
 */
interface CompactVariantProps {
  /**
   * The visual variant of the radio button group.
   * `compact`: Radio buttons in a bordered container with dividers
   */
  variant: "compact";

  /**
   * The items for the compact variant
   */
  items: CompactItem[];
}

/**
 * Discriminated union of all variant props
 */
type RadioButtonFieldsetVariantProps =
  | TileVariantProps
  | TextVariantProps
  | CompactVariantProps;

/**
 * Custom props for RadioButtonFieldset (non-variant specific)
 */
interface RadioButtonFieldsetCustomProps {
  /**
   * The legend configuration (acts as the accessible name for the radio group).
   * Internally rendered as a legend element for proper fieldset semantics.
   */
  legend?: RadioButtonFieldsetLegend;

  /**
   * The hint configuration (displayed below the legend)
   */
  hint?: RadioButtonFieldsetHint;

  /**
   * The validation message configuration (displayed below the legend/hint, before the radio group)
   */
  validationMessage?: RadioButtonFieldsetValidationMessage;

  /**
   * Whether a selection is required. Adds required indicator to legend and sets aria-required.
   */
  required?: boolean;

  /**
   * Whether all radio buttons in the group are disabled.
   */
  disabled?: boolean;

  /**
   * Whether the radio group is read-only.
   */
  readOnly?: boolean;
}

// Keys to omit from RadioGroupProps (including is-prefixed props we're replacing and orientation)
type AriaPropsToOmit =
  | "children"
  | "isRequired"
  | "isDisabled"
  | "isReadOnly"
  | "orientation";

/**
 * Variant-specific prop keys
 */
type VariantPropKeys =
  | keyof TileVariantProps
  | keyof TextVariantProps
  | keyof CompactVariantProps;

/**
 * Base props shared by all variants (Aria props minus omitted + custom props)
 */
type RadioButtonFieldsetBaseProps = Omit<
  RadioGroupProps,
  AriaPropsToOmit | VariantPropKeys
> &
  RadioButtonFieldsetCustomProps;

export type RadioButtonFieldsetProps = RadioButtonFieldsetBaseProps &
  RadioButtonFieldsetVariantProps;

/**
 * Renders items based on the variant.
 * Accepts the full props to preserve TypeScript's discriminated union narrowing.
 */
const renderItems = (props: RadioButtonFieldsetProps): React.ReactNode => {
  switch (props.variant) {
    case "tile":
      return props.items.map((item) => (
        <RadioButtonTile key={item.value} {...item} />
      ));

    case "text":
      return props.items.map((item) => (
        <RadioButton
          key={item.value}
          {...item}
          label={{ variant: "normal", ...item.label }}
        />
      ));

    case "compact":
      return props.items.map((item) => (
        <_RadioButtonCompact key={item.value} {...item} hideFocusRing />
      ));
  }
};

/**
 * A fieldset-like container for a group of radio buttons with accessible labeling.
 *
 * This component wraps React Aria's RadioGroup to provide:
 * - Proper `role="radiogroup"` semantics
 * - Accessible name from the legend
 * - `aria-describedby` for hint text
 * - `aria-invalid` when validation message has variant="invalid"
 * - `aria-required` when required is true
 * - Full keyboard navigation (Arrow keys, Tab, Space)
 *
 * @example
 * // Tile variant
 * <RadioButtonFieldset
 *   variant="tile"
 *   legend={{ children: "Choose a plan" }}
 *   items={[
 *     { value: "basic", label: { children: "Basic" }, hint: { children: "For individuals" } },
 *     { value: "pro", label: { children: "Pro" }, hint: { children: "For teams" } },
 *   ]}
 * />
 *
 * @example
 * // Text variant
 * <RadioButtonFieldset
 *   variant="text"
 *   legend={{ children: "Notification preference" }}
 *   items={[
 *     { value: "email", label: { children: "Email" } },
 *     { value: "sms", label: { children: "SMS" } },
 *   ]}
 * />
 *
 * @example
 * // Compact variant
 * <RadioButtonFieldset
 *   variant="compact"
 *   legend={{ children: "Notification preference" }}
 *   items={[
 *     { value: "email", label: { children: "Email" } },
 *     { value: "sms", label: { children: "SMS" } },
 *   ]}
 * />
 *
 * @see https://react-spectrum.adobe.com/react-aria/RadioGroup.html
 * @see https://developer.mozilla.org/en-US/docs/Web/Accessibility/ARIA/Reference/Roles/radiogroup_role
 */
export const RadioButtonFieldset = forwardRef<
  HTMLDivElement,
  RadioButtonFieldsetProps
>((props, ref) => {
  const {
    variant,
    legend,
    hint,
    validationMessage,
    className,
    required,
    disabled,
    readOnly,
    ...radioGroupProps
  } = props;

  const generatedId = useId();
  const hintId = hint ? `${generatedId}-hint` : undefined;
  const validationMessageId = validationMessage
    ? `${generatedId}-validation`
    : undefined;

  // Build aria-describedby from hint and validation message IDs
  const describedByIds = [hintId, validationMessageId].filter(
    Boolean
  ) as string[];
  const ariaDescribedBy =
    describedByIds.length > 0 ? describedByIds.join(" ") : undefined;

  // Determine if the radio group is in an invalid state
  const isInvalid = validationMessage?.variant === "invalid";

  // Determine required state: use legend.required if explicitly set, otherwise fall back to required
  const legendRequired = legend?.required ?? required ?? false;

  return (
    <RadioGroup
      ref={ref}
      className={clsx(styles.radioButtonFieldset, className)}
      invalid={isInvalid}
      {...(required !== undefined && { required })}
      {...(disabled !== undefined && { disabled })}
      {...(readOnly !== undefined && { readOnly })}
      {...(ariaDescribedBy !== undefined && {
        "aria-describedby": ariaDescribedBy,
      })}
      {...radioGroupProps}
    >
      {(legend || hint) && (
        <div className={styles.legendHintStack}>
          {legend && (
            <Legend {...legend} asChild required={legendRequired}>
              <AriaLabel>{legend.children}</AriaLabel>
            </Legend>
          )}
          {hint && (
            <Text elementType="div" slot="description" id={hintId}>
              <Hint {...hint} />
            </Text>
          )}
        </div>
      )}
      {validationMessage && (
        <div className={styles.validationMessageContainer}>
          <ValidationMessage id={validationMessageId} {...validationMessage}>
            {validationMessage.children}
          </ValidationMessage>
        </div>
      )}
      <div className={styles.radioGroupContainer({ variant })}>
        {renderItems(props)}
      </div>
    </RadioGroup>
  );
});

RadioButtonFieldset.displayName = "RadioButtonFieldset";
