import type { RadioButtonTileProps } from "../RadioButtonTile";
import type { RadioButtonProps } from "../RadioButton";
import type { RadioButtonCompactProps } from "./components/_RadioButtonCompact";

export const RadioButtonFieldsetVariants = ["tile", "text", "compact"] as const;
export type RadioButtonFieldsetVariant =
  (typeof RadioButtonFieldsetVariants)[number];

export const DEFAULT_RADIO_BUTTON_FIELDSET_VARIANT: RadioButtonFieldsetVariant =
  "tile";

/**
 * Item shape for the tile variant.
 * Uses RadioButtonTile internally.
 */
export type TileItem = Omit<RadioButtonTileProps, "hideFocusRing">;

/**
 * Item shape for the text variant.
 * Uses RadioButton internally.
 */
export type TextItem = Omit<RadioButtonProps, "hideFocusRing">;

/**
 * Item shape for the compact variant.
 * Uses internal _RadioButtonCompact component.
 */
export type CompactItem = Omit<RadioButtonCompactProps, "hideFocusRing">;
